import pandas as pd

df = pd.DataFrame(var_call_o72gTxUcpku0FUw6F44P0qdV)
pat = re.compile(r"\b([A-Z]{2})\b")

def extract_state(desc):
    if not isinstance(desc,str):
        return None
    m = re.search(r"\bin\s+[^,]+,\s*([A-Z]{2})\b", desc)
    if m:
        return m.group(1)
    m = re.search(r"\b([A-Z]{2})\b(?=,\s*this)", desc)
    if m:
        return m.group(1)
    # fallback: last two-letter token
    tokens = pat.findall(desc)
    return tokens[-1] if tokens else None

states = df['description'].map(extract_state)
print('__RESULT__:')
print(json.dumps(states.value_counts(dropna=False).to_dict()))

